1	import { useMemo } from "react";
2	import { useMarkets, useMarket, useEngineStats } from "@/lib/query/hooks";
3	import { formatProbability } from "@/lib/utils/format";
4	import type { MarketSummary } from "@/lib/api/types";
5	
6	interface GraphNode {
7	  id: string;
8	  title: string;
9	  x: number;
10	  y: number;
11	  marginals: Record<string, number>;
12	  outcomeName: string;
13	  status: string;
14	}
15	
16	interface GraphEdge {
17	  from: string;
18	  to: string;
19	  label?: string;
20	}
21	
22	interface BayesNetGraphProps {
23	  /** The currently viewed market — highlighted in the graph */
24	  focusMarketId?: string;
25	  /** Edges derived from conditional edits */
26	  conditionalEdges?: GraphEdge[];
27	}
28	
29	const NODE_W = 160;
30	const NODE_H = 72;
31	const PADDING = 40;
32	
33	function layoutNodes(markets: MarketSummary[]): GraphNode[] {
34	  // Arrange in a circle for small N, grid for larger
35	  const n = markets.length;
36	  if (n === 0) return [];
37	
38	  const cx = 300;
39	  const cy = 200;
40	  const radius = Math.max(120, n * 40);
41	
42	  return markets.map((m, i) => {
43	    const angle = (2 * Math.PI * i) / n - Math.PI / 2;
44	    return {
45	      id: m.id,
46	      title: m.title.length > 28 ? m.title.slice(0, 26) + "…" : m.title,
47	      x: cx + radius * Math.cos(angle),
48	      y: cy + radius * Math.sin(angle),
49	      marginals: {},
50	      outcomeName: "",
51	      status: m.status,
52	    };
53	  });
54	}
55	
56	function MarketNode({
57	  node,
58	  isFocus,
59	  detail,
60	}: {
61	  node: GraphNode;
62	  isFocus: boolean;
63	  detail?: { marginals: Record<string, number>; outcomes: Array<{ id: string; name: string }> };
64	}) {
65	  const borderColor = isFocus ? "var(--color-primary)" : "var(--color-border)";
66	  const bg = isFocus ? "var(--color-bg-surface)" : "var(--color-bg)";
67	
68	  return (
69	    <g transform={`translate(${node.x - NODE_W / 2}, ${node.y - NODE_H / 2})`}>
70	      <rect
71	        width={NODE_W}
72	        height={NODE_H}
73	        rx={8}
74	        fill={bg}
75	        stroke={borderColor}
76	        strokeWidth={isFocus ? 2.5 : 1}
77	      />
78	      <text
79	        x={NODE_W / 2}
80	        y={18}
81	        textAnchor="middle"
82	        fontSize="11"
83	        fontWeight={600}
84	        fill="var(--color-text)"
85	      >
86	        {node.title}
87	      </text>
88	      {/* Mini probability bars */}
89	      {detail && detail.outcomes.length > 0 && (
90	        <g transform="translate(8, 28)">
91	          {detail.outcomes.slice(0, 3).map((o, i) => {
92	            const p = detail.marginals[o.id] ?? 0;
93	            const barW = NODE_W - 16;
94	            return (
95	              <g key={o.id} transform={`translate(0, ${i * 14})`}>
96	                <rect width={barW} height={10} rx={3} fill="var(--color-border)" opacity={0.3} />
97	                <rect
98	                  width={Math.max(2, barW * p)}
99	                  height={10}
100	                  rx={3}
101	                  fill={p > 0.5 ? "var(--color-success)" : "var(--color-info)"}
102	                  opacity={0.7}
103	                />
104	                <text x={4} y={8} fontSize="8" fill="var(--color-text)" fontWeight={500}>
105	                  {o.name}: {formatProbability(p)}
106	                </text>
107	              </g>
108	            );
109	          })}
110	        </g>
111	      )}
112	      {/* Status dot */}
113	      <circle
114	        cx={NODE_W - 10}
115	        cy={10}
116	        r={4}
117	        fill={
118	          node.status === "active"
119	            ? "var(--color-success)"
120	            : node.status === "resolved"
121	              ? "var(--color-info)"
122	              : "var(--color-text-muted)"
123	        }
124	      />
125	    </g>
126	  );
127	}
128	
129	function EdgeLine({ from, to, nodes }: { from: string; to: string; nodes: GraphNode[] }) {
130	  const a = nodes.find((n) => n.id === from);
131	  const b = nodes.find((n) => n.id === to);
132	  if (!a || !b) return null;
133	
134	  // Arrow from a → b
135	  const dx = b.x - a.x;
136	  const dy = b.y - a.y;
137	  const dist = Math.sqrt(dx * dx + dy * dy);
138	  if (dist === 0) return null;
139	
140	  const ux = dx / dist;
141	  const uy = dy / dist;
142	
143	  // Start/end offset by node radius
144	  const startX = a.x + ux * (NODE_W / 2 + 4);
145	  const startY = a.y + uy * (NODE_H / 2 + 4);
146	  const endX = b.x - ux * (NODE_W / 2 + 8);
147	  const endY = b.y - uy * (NODE_H / 2 + 8);
148	
149	  return (
150	    <g>
151	      <line
152	        x1={startX}
153	        y1={startY}
154	        x2={endX}
155	        y2={endY}
156	        stroke="var(--color-primary)"
157	        strokeWidth={1.5}
158	        strokeDasharray="6 3"
159	        opacity={0.6}
160	      />
161	      {/* Arrowhead */}
162	      <polygon
163	        points={`${endX},${endY} ${endX - ux * 8 - uy * 4},${endY - uy * 8 + ux * 4} ${endX - ux * 8 + uy * 4},${endY - uy * 8 - ux * 4}`}
164	        fill="var(--color-primary)"
165	        opacity={0.6}
166	      />
167	    </g>
168	  );
169	}
170	
171	function CliqueOverlay({
172	  clique,
173	  nodes,
174	}: {
175	  clique: { id: string; nodes: string[] };
176	  nodes: GraphNode[];
177	}) {
178	  const memberNodes = nodes.filter((n) => clique.nodes.includes(n.id));
179	  if (memberNodes.length < 2) return null;
180	
181	  // Draw a rounded rectangle around the clique members
182	  const xs = memberNodes.map((n) => n.x);
183	  const ys = memberNodes.map((n) => n.y);
184	  const pad = 20;
185	  const minX = Math.min(...xs) - NODE_W / 2 - pad;
186	  const minY = Math.min(...ys) - NODE_H / 2 - pad;
187	  const maxX = Math.max(...xs) + NODE_W / 2 + pad;
188	  const maxY = Math.max(...ys) + NODE_H / 2 + pad;
189	
190	  return (
191	    <g>
192	      <rect
193	        x={minX}
194	        y={minY}
195	        width={maxX - minX}
196	        height={maxY - minY}
197	        rx={12}
198	        fill="var(--color-primary)"
199	        fillOpacity={0.06}
200	        stroke="var(--color-primary)"
201	        strokeWidth={1}
202	        strokeDasharray="4 4"
203	        strokeOpacity={0.3}
204	      />
205	      <text x={minX + 6} y={minY + 14} fontSize="9" fill="var(--color-primary)" opacity={0.7}>
206	        Clique {clique.id}
207	      </text>
208	    </g>
209	  );
210	}
211	
212	/** Renders a mini detail-fetcher node that uses useMarket */
213	function NodeWithDetail({
214	  node,
215	  isFocus,
216	}: {
217	  node: GraphNode;
218	  isFocus: boolean;
219	}) {
220	  const { data } = useMarket(node.id);
221	  const detail = data
222	    ? { marginals: data.market.marginals, outcomes: data.market.outcomes }
223	    : undefined;
224	  return <MarketNode node={node} isFocus={isFocus} detail={detail} />;
225	}
226	
227	export function BayesNetGraph({
228	  focusMarketId,
229	  conditionalEdges = [],
230	}: BayesNetGraphProps) {
231	  const { data: marketsData, isLoading } = useMarkets();
232	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
233	
234	  const markets = marketsData?.markets ?? [];
235	  const nodes = useMemo(() => layoutNodes(markets), [markets]);
236	  const cliques = engineStats?.cliques.cliques ?? [];
237	
238	  if (isLoading) {
239	    return (
240	      <div style={panelStyle}>
241	        <div style={{ color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-lg)" }}>
242	          Loading network...
243	        </div>
244	      </div>
245	    );
246	  }
247	
248	  if (markets.length === 0) {
249	    return (
250	      <div style={panelStyle}>
251	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
252	          No markets to visualize.
253	        </div>
254	      </div>
255	    );
256	  }
257	
258	  // Compute SVG viewBox from node positions
259	  const xs = nodes.map((n) => n.x);
260	  const ys = nodes.map((n) => n.y);
261	  const vbX = Math.min(...xs) - NODE_W / 2 - PADDING;
262	  const vbY = Math.min(...ys) - NODE_H / 2 - PADDING;
263	  const vbW = Math.max(...xs) - Math.min(...xs) + NODE_W + PADDING * 2;
264	  const vbH = Math.max(...ys) - Math.min(...ys) + NODE_H + PADDING * 2;
265	
266	  return (
267	    <div style={panelStyle}>
268	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
269	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
270	          Bayesian Network
271	        </h3>
272	        <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
273	          {markets.length} variable{markets.length !== 1 ? "s" : ""}
274	          {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
275	          {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
276	          {engineStats && ` · JT width ${engineStats.cliques.junction_tree_width}`}
277	        </div>
278	      </div>
279	
280	      <svg
281	        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
282	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
283	      >
284	        {/* Clique overlays (behind edges/nodes) */}
285	        {cliques.map((c) => (
286	          <CliqueOverlay key={c.id} clique={c} nodes={nodes} />
287	        ))}
288	
289	        {/* Conditional edges */}
290	        {conditionalEdges.map((e, i) => (
291	          <EdgeLine key={`${e.from}-${e.to}-${i}`} from={e.from} to={e.to} nodes={nodes} />
292	        ))}
293	
294	        {/* Market nodes */}
295	        {nodes.map((node) => (
296	          <NodeWithDetail
297	            key={node.id}
298	            node={node}
299	            isFocus={node.id === focusMarketId}
300	          />
301	        ))}
302	      </svg>
303	
304	      {/* Legend */}
305	      <div style={{ display: "flex", gap: "var(--space-md)", fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
306	        <span>
307	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-success)", marginRight: 4 }} />
308	          Active
309	        </span>
310	        <span>
311	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-info)", marginRight: 4 }} />
312	          Resolved
313	        </span>
314	        {conditionalEdges.length > 0 && (
315	          <span>
316	            <span style={{ display: "inline-block", width: 16, height: 2, background: "var(--color-primary)", marginRight: 4, verticalAlign: "middle" }} />
317	            Conditional dependency
318	          </span>
319	        )}
320	        {cliques.length > 0 && (
321	          <span>
322	            <span style={{ display: "inline-block", width: 12, height: 12, border: "1px dashed var(--color-primary)", borderRadius: 3, marginRight: 4, verticalAlign: "middle", opacity: 0.5 }} />
323	            Junction tree clique
324	          </span>
325	        )}
326	      </div>
327	    </div>
328	  );
329	}
330	
331	const panelStyle: React.CSSProperties = {
332	  padding: "var(--space-md)",
333	  borderRadius: "var(--radius-md)",
334	  border: "1px solid var(--color-border)",
335	  background: "var(--color-bg-surface)",
336	};
